sql:
SELECT patent_number, filing_date, COUNT(DISTINCT technical_field) AS unique_fields
FROM patents
GROUP BY patent_number, filing_date;

SELECT patent_id, COUNT(claim_id) AS total_claims
FROM patent_claims
GROUP BY patent_id;

SELECT AVG(inventor_count) AS average_inventors_per_patent
FROM (
  SELECT patent_id, COUNT(inventor_id) AS inventor_count
  FROM patent_inventors
  GROUP BY patent_id
) AS inventor_counts;

SELECT patent_id, AVG(fee_amount) AS average_fee, COUNT(fee_id) AS fee_count
FROM patent_maintenance_fees
GROUP BY patent_id;

